// // This module is designed to store a single bit in a DRAM cell. It has inputs for clock, write enable, and data in, and an output for data out. When write enable is high, data in is written to data out on the rising edge of the clock.
module dram_cell (  
    input wire clk,  
    input wire write_enable,  
    input wire data_in,  
    output reg data_out  
);  
    always @(posedge clk) begin  
        if (write_enable) begin  
            data_out <= data_in;  
        end  
    end  
endmodule
